// **********************************************************
// @description Generate userID from Payload
//
// @param   {object} data - payload
// @param   {object} $    - {tenant, paramsId, endpointId, endpointConfig}
// @param   {object} ctx  - opentracing context
// @param   {object} this - ARES
//
// @return  {object} data - payload decorated
// **********************************************************

const indexName = "utenti";
const action = "_search";
const environment = process.env.ARES_ENVIRONMENT ?? "TEST";
const settings = {
  PROD:{
    token:"YXJlcy1kZWNvcmF0b3I6RTh2aHJqeWRzWjpqZ2wqPw==",
    url:`https://vpc-prod-ares-es-domain-46dhp5roary3finmmp5xtntsvy.eu-west-1.es.amazonaws.com/${indexName}/${action}`
  },
  TEST:{
    token:"YXJlcy1kZWNvcmF0b3I6Rk95bTU4Nmh3N0hXMXR6fQ==",
    url:`https://vpc-test-ares-es-domain-kwqpzbvm4h64in2iyr4prx6bhe.eu-west-1.es.amazonaws.com/${indexName}/${action}`
  }
}

if (data.query && data.query.userId && data.query.personaShortId && !data.query.originalUserId) {
  data.query.familyId = data.query.userId;
  data.query.userId = `${data.query.userId}:${decodeURIComponent(data.query.personaShortId)}`;

  const url = settings[environment].url;
  const token = settings[environment].token;

  const clusterResponse = await this.axios
    ({
      url,
      method: "POST",
      headers: {
        'X-Custom-Ares': 'cluster_input_decorator',
        "Authorization": `Basic ${token}`
      },
      data: {
        query: {
          ids: {
            values: [data.query.userId ],
          },
        },
      },
    })
    .catch((error) => {
      this.logger.error({
        function: "axiosGetClusterIDs",
        errorMessage: error.message,
        error: `CLUSTERS DECORATOR GET ${url}`,
      });
    });

  if (clusterResponse?.data?.hits?.total?.value > 0) {
    const { is_outlier, cluster_id } = clusterResponse.data.hits.hits[0]._source;

    data.query.unifiedClusterId = cluster_id;
    data.query.isOutlier = is_outlier;

    // Force No Cache if is an Outliner
    if(is_outlier){
      data.query.cache = "false"
    }
  }

  // Fill Cluster Metadata to let ARES inject response metadata
  data.clusterMetadata = {
    familyId: data.query.familyId,
    userId: data.query.userId,
    unifiedClusterId: data.query.unifiedClusterId,
    isOutlier: data.query.isOutlier,
  };
}

return data;
